class Student {
    // STATE — instance variables
    String name;
    int roll;
    int marks;

    // BEHAVIOR — methods
    public void display() {
        System.out.println("Name: " + name + ", Roll: " + roll);
    }

    public String calculateGrade() {
        if (marks >= 90) return "A";
        else if (marks >= 75) return "B";
        else return "C";
    }
}

public class Main {
    public static void main(String[] args) {
        Student s1 = new Student();
        s1.name = "Harsh";
        s1.marks = 95;

        Student s2 = new Student();
        s2.name = "Harsh";   // same name
        s2.marks = 95;        // same marks

        // IDENTITY — same state but different objects
        System.out.println(s1 == s2);  // false — different references
        s1.display();                  // BEHAVIOR
    }
}

public class Main {
    public static void main(String[] args) {
        // 'harsh' is a reference on the STACK
        // new Student() creates object on the HEAP
        Student harsh = new Student();
        harsh.name = "Harsh";
        harsh.marks = 100;

        // s2 is a NEW reference pointing to SAME heap object
        Student s2 = harsh;
        s2.marks = 50;  // modifies the same object!

        System.out.println(harsh.marks);  // 50 — NOT 100 anymore!
        System.out.println(s2 == harsh);  // true — same reference

        // Array of references — references on stack, objects on heap
        Student[] students = new Student[3];
        System.out.println(students[0]);  // null — object not created yet

        students[0] = new Student();      // now object created on heap
    }
}

class Student {
    String name;
    int roll;
    int marks;

    // DEFAULT constructor — no parameters
    Student() {
        this.name = "Unknown";
        this.roll = 0;
        this.marks = 0;
    }

    // PARAMETERIZED constructor — set values at creation time
    Student(String name, int roll, int marks) {
        this.name = name;
        this.roll = roll;
        this.marks = marks;
    }

    // COPY constructor — create new object from existing one
    Student(Student other) {
        this.name = other.name;
        this.roll = other.roll;
        this.marks = other.marks;
    }
}

public class Main {
    public static void main(String[] args) {
        Student s1 = new Student();                    // default
        Student s2 = new Student("Harsh", 9, 100);    // parameterized
        Student s3 = new Student(s2);                  // copy

        s3.marks = 50;  // modifying copy does NOT affect s2
        System.out.println(s2.marks);  // 100 — unchanged
        System.out.println(s3.marks);  // 50
    }
}

class Student {
    String name;
    int roll;
    int marks;

    // USE 1: Resolve naming conflict between parameter and field
    Student(String name, int roll, int marks) {
        this.name = name;   // 'this.name' is the field, 'name' is the parameter
        this.roll = roll;
        this.marks = marks;
    }

    // USE 2: this() — call another constructor (constructor chaining)
    Student(String name) {
        this(name, 0, 0);  // calls the 3-param constructor above
        // must be FIRST statement — compiler error if not
    }

    // USE 3: Return current object for method chaining
    Student setMarks(int marks) {
        this.marks = marks;
        return this;  // returns the same object
    }

    Student setRoll(int roll) {
        this.roll = roll;
        return this;
    }
}

public class Main {
    public static void main(String[] args) {
        // Method chaining using 'this'
        Student s = new Student("Harsh").setMarks(100).setRoll(9);
        System.out.println(s.name + ", " + s.roll + ", " + s.marks);
        // Output: Harsh, 9, 100
    }
}

// What happens step by step:
// Student harsh = new Student("Harsh", 9, 100);

// STEP 1: JVM allocates heap memory for Student object
//         Memory zeroed: name=null, roll=0, marks=0

// STEP 2: Constructor called with ("Harsh", 9, 100)
//         this.name = "Harsh"
//         this.roll = 9
//         this.marks = 100

// STEP 3: Memory address of object returned, stored in 'harsh'
//         harsh → [0x7f4a... pointing to heap object]

public class Main {
    public static void main(String[] args) {
        Student harsh = new Student("Harsh", 9, 100);

        // harsh is just a reference — not the object itself
        // You cannot do: harsh + 1  (no pointer arithmetic)

        // Creating object without assigning — GC will collect it
        new Student("temp", 0, 0);  // created but immediately eligible for GC

        // Two references to same object
        Student s2 = harsh;
        System.out.println(harsh == s2);  // true — same heap address
    }
}

class BankAccount {
    private double balance;    // private — only this class can touch it
    private String accountNo; // private

    public BankAccount(String accountNo, double initialBalance) {
        this.accountNo = accountNo;
        // Validate at creation time
        if (initialBalance < 0) throw new IllegalArgumentException("Balance cannot be negative");
        this.balance = initialBalance;
    }

    // PUBLIC getter — read-only access
    public double getBalance() {
        return balance;
    }

    // PUBLIC setter — with validation
    public void deposit(double amount) {
        if (amount <= 0) throw new IllegalArgumentException("Deposit must be positive");
        this.balance += amount;
    }

    // PRIVATE helper — internal use only
    private void logTransaction(double amount) {
        System.out.println("Transaction: " + amount + " on " + accountNo);
    }
}

