// GOOD encapsulation — fields are private
class GoodStudent {
    private String name;
    private int age;
    private int marks;

    public GoodStudent(String name, int age, int marks) {
        setAge(age);      // validation even in constructor
        setMarks(marks);
        this.name = name;
    }

    public int getAge() { return age; }

    public void setAge(int age) {
        if (age < 0 || age > 150)
            throw new IllegalArgumentException("Invalid age: " + age);
        this.age = age;
    }

    public int getMarks() { return marks; }

    public void setMarks(int marks) {
        if (marks < 0 || marks > 100)
            throw new IllegalArgumentException("Marks must be 0-100");
        this.marks = marks;
    }
}

