class Student {
    // INSTANCE variable — one per object
    private String name;
    private int marks;

    // STATIC variable — one for the entire class, shared by all objects
    private static int totalStudents = 0;

    Student(String name, int marks) {
        this.name = name;
        this.marks = marks;
        totalStudents++;  // increments the shared counter
    }

    // INSTANCE method — needs an object to call
    public void display() {
        System.out.println(name + ": " + marks);
    }

    // STATIC method — no object needed, cannot access 'name' or 'marks'
    public static int getTotalStudents() {
        // System.out.println(name); // COMPILER ERROR — name is instance variable
        return totalStudents;
    }
}

public class Main {
    public static void main(String[] args) {
        System.out.println(Student.getTotalStudents()); // 0 — no object needed

        Student s1 = new Student("Harsh", 100);
        Student s2 = new Student("Alex", 85);

        System.out.println(Student.getTotalStudents()); // 2
        System.out.println(s1.getTotalStudents());      // 2 — same value (avoid this style)
    }
}

// Abstract class — partial blueprint
abstract class Shape {
    String color;

    // CONCRETE constructor — called from subclasses via super()
    Shape(String color) {
        this.color = color;
    }

    // ABSTRACT method — must be implemented by subclasses
    abstract double area();
    abstract double perimeter();

    // CONCRETE method — shared by all shapes, no override needed
    public void displayColor() {
        System.out.println("Color: " + color);
    }

    // STATIC method — allowed in abstract class
    public static String getCategory() {
        return "Geometric Shape";
    }
}

class Circle extends Shape {
    double radius;

    Circle(String color, double radius) {
        super(color);  // calls abstract class constructor
        this.radius = radius;
    }

    @Override
    public double area() { return Math.PI * radius * radius; }

    @Override
    public double perimeter() { return 2 * Math.PI * radius; }
}

