// AGGREGATION — weak relationship, Library does NOT own Books
class Book {
    String title;
    Book(String title) { this.title = title; }
}

class Library {
    private List<Book> books;  // Library holds reference but didn't create books

    // Books passed in from outside — Library doesn't own them
    Library(List<Book> books) {
        this.books = books;
    }
    // If Library is destroyed, Book objects still exist in memory
}

// COMPOSITION — strong relationship, House OWNS Rooms
class Room {
    String name;
    Room(String name) { this.name = name; }
}

class House {
    private List<Room> rooms;

    House() {
        // House CREATES and manages Room objects
        rooms = new ArrayList<>();
        rooms.add(new Room("Living Room"));
        rooms.add(new Room("Bedroom"));
        // If House object is destroyed, these Room objects have no owner
        // and will be garbage collected — they cannot exist independently
    }
}

