public class Main {
    // This method works with ANY Notification subtype — LSP in action
    static void notifyUser(Notification notif) {
        notif.sendNotification();  // calls correct version at runtime
    }

    public static void main(String[] args) {
        // Substituting subclass for parent — all work correctly
        notifyUser(new Notification());        // Sending Email Notification
        notifyUser(new TextNotification());    // Sending Text Notification
        notifyUser(new WhatsAppNotification()); // Sending WhatsApp Notification

        // Runtime polymorphism:
        Notification n = new TextNotification();
        // Left side (Notification) decides what methods are accessible
        // Right side (TextNotification) decides which version runs at runtime
        n.sendNotification();  // Output: Sending Text Notification
    }
}

