class Notification {
    public void sendNotification() {
        System.out.println("Send Email Notif");
    }
}

class TextNotification extends Notification {
    @Override
    public void sendNotification() {
        System.out.println("Send Text Notif");  // overridden version
    }

    public void sendSMS() {  // method ONLY in TextNotification
        System.out.println("Sending SMS directly");
    }
}

public class Main {
    public static void main(String[] args) {
        // LEFT = Notification (compiler checks here)
        // RIGHT = TextNotification (JVM uses this at runtime)
        Notification notif = new TextNotification();

        notif.sendNotification();  // Output: Send Text Notif (child version runs)
        // Compile: does Notification have sendNotification()? YES → OK
        // Runtime: is object TextNotification? YES → use overridden version

        // notif.sendSMS();  // COMPILE ERROR
        // Compile: does Notification have sendSMS()? NO → reject
        // Compiler doesn't know/trust what's on the right side

        // To call sendSMS(), need to downcast:
        ((TextNotification) notif).sendSMS();  // works but use carefully

        // Case: not overridden
        Notification notif2 = new TextNotification();
        // If TextNotification had NOT overridden sendNotification():
        // notif2.sendNotification() → Output: Send Email Notif (parent version)
    }
}

class Calculator {
    // METHOD OVERLOADING — same name, different parameters
    // Resolved at COMPILE TIME — compiler sees the argument types
    public int add(int a, int b) {
        return a + b;
    }

    public double add(double a, double b) {  // different param types
        return a + b;
    }

    public int add(int a, int b, int c) {    // different param count
        return a + b + c;
    }
}

class Animal {
    // METHOD OVERRIDING — child provides new implementation
    public void makeSound() {
        System.out.println("Some generic animal sound");
    }
}

class Dog extends Animal {
    @Override
    public void makeSound() {  // exact same signature
        System.out.println("Woof!");
    }
}

class Cat extends Animal {
    @Override
    public void makeSound() {
        System.out.println("Meow!");
    }
}

public class Main {
    public static void main(String[] args) {
        // Overloading — resolved at compile time
        Calculator calc = new Calculator();
        calc.add(1, 2);        // compiler picks int version
        calc.add(1.5, 2.5);    // compiler picks double version

        // Overriding — resolved at runtime
        Animal a1 = new Dog();
        Animal a2 = new Cat();
        a1.makeSound();  // Woof! — runtime decision
        a2.makeSound();  // Meow! — runtime decision
    }
}

