public class Main {
    public static void main(String[] args) {
        // PRIMITIVES — == compares values
        int a = 5, b = 5;
        System.out.println(a == b);  // true — same value

        // OBJECTS — == compares references (memory addresses)
        String s1 = new String("hello");
        String s2 = new String("hello");
        System.out.println(s1 == s2);      // false — different objects
        System.out.println(s1.equals(s2)); // true — String overrides equals()

        // String pool special case
        String s3 = "hello";  // from string pool
        String s4 = "hello";  // same pool entry
        System.out.println(s3 == s4);  // true — same reference from pool

        // Custom class without overriding equals()
        Student st1 = new Student("Harsh", 9);
        Student st2 = new Student("Harsh", 9);
        System.out.println(st1 == st2);      // false — different objects
        System.out.println(st1.equals(st2)); // false — uses Object's equals (reference)
    }
}

class Student {
    String name; int roll;
    Student(String name, int roll) { this.name = name; this.roll = roll; }
    // To fix: override equals() and hashCode() together
    @Override
    public boolean equals(Object o) {
        if (this == o) return true;
        if (!(o instanceof Student)) return false;
        Student s = (Student) o;
        return roll == s.roll && name.equals(s.name);
    }
}

public class Main {
    public static void main(String[] args) {
        // AUTOBOXING — primitive → wrapper object automatically
        int primitive = 42;
        Integer wrapped = primitive;  // Java does: Integer.valueOf(42)
        System.out.println(wrapped);  // 42

        // UNBOXING — wrapper object → primitive automatically
        Integer boxed = Integer.valueOf(100);
        int unboxed = boxed;  // Java does: boxed.intValue()
        System.out.println(unboxed + 5);  // 105

        // Why needed — collections require objects
        List<Integer> list = new ArrayList<>();
        list.add(1);   // autoboxed: int → Integer
        list.add(2);
        int sum = list.get(0) + list.get(1);  // unboxed: Integer → int

        // THE TRAP — NullPointerException from unboxing null
        Integer nullableValue = null;  // valid — Integer can be null
        // int result = nullableValue;  // NullPointerException at runtime!
        // Looks like simple assignment but JVM tries nullableValue.intValue() → crash

        // Safe way:
        if (nullableValue != null) {
            int result = nullableValue;  // safe unboxing
        }

        // Integer caching gotcha:
        Integer x = 127;
        Integer y = 127;
        System.out.println(x == y);  // true — cached range -128 to 127

        Integer x2 = 200;
        Integer y2 = 200;
        System.out.println(x2 == y2);  // false — outside cache range, different objects
        System.out.println(x2.equals(y2));  // true — use equals for content comparison
    }
}

public class Main {
    public static void main(String[] args) {
        // String POOL — literals share references
        String s1 = "hello";    // created in pool
        String s2 = "hello";    // reuses same pool entry
        System.out.println(s1 == s2);  // true — same reference

        // new String — forces creation outside pool
        String s3 = new String("hello");  // on heap, NOT in pool
        System.out.println(s1 == s3);     // false — different objects
        System.out.println(s1.equals(s3)); // true — same content

        // IMMUTABILITY — operations return NEW strings
        String original = "Hello";
        String upper = original.toUpperCase();
        System.out.println(original);  // Hello — unchanged!
        System.out.println(upper);     // HELLO — new object

        // Concatenation performance trap
        String result = "";
        for (int i = 0; i < 1000; i++) {
            result += i;  // creates 1000 new String objects — SLOW
        }

        // StringBuilder — mutable, no new objects, much faster
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < 1000; i++) {
            sb.append(i);  // modifies same object
        }
        String finalResult = sb.toString();  // one String at the end
    }
}

// Analogy in code terms:

// PROGRAM = the .java/.class file sitting on disk
// Just bytes, not running

// PROCESS = JVM instance running your program
// Has its own heap, method area, etc.
// You can run two JVMs = two separate processes

// THREAD = individual execution path within the JVM
public class Main {
    public static void main(String[] args) {
        // main() itself runs on the 'main' thread
        // When you create threads, they share the same heap

        // Shared data — ALL threads can access this
        int[] sharedCounter = {0};

        Thread t1 = new Thread(() -> {
            for (int i = 0; i < 1000; i++) sharedCounter[0]++;
        });

        Thread t2 = new Thread(() -> {
            for (int i = 0; i < 1000; i++) sharedCounter[0]++;
        });

        t1.start();
        t2.start();

        // Both t1 and t2 share sharedCounter — same heap memory
        // This is POWERFUL (easy communication) but DANGEROUS (race conditions)
        // Expected: 2000, Actual: could be anything < 2000 without synchronization
    }
}

public class ContextSwitchDemo {
    public static void main(String[] args) throws InterruptedException {
        // With 2 threads on a single core:
        // Core executes T1 for a time slice
        // OS saves T1 state, loads T2 state → context switch
        // Core executes T2 for a time slice
        // OS saves T2 state, loads T1 state → context switch
        // Repeat — both threads make progress but not simultaneously

        Thread t1 = new Thread(() -> {
            for (int i = 0; i < 5; i++) {
                System.out.println("T1 executing: " + i);
                // OS may context switch away from T1 at any point here
            }
        });

        Thread t2 = new Thread(() -> {
            for (int i = 0; i < 5; i++) {
                System.out.println("T2 executing: " + i);
                // T2 may interleave with T1 unpredictably
            }
        });

        t1.start();
        t2.start();

        // Output order is NON-DETERMINISTIC — OS decides
        // Possible output:
        // T1 executing: 0
        // T2 executing: 0
        // T1 executing: 1
        // T2 executing: 1  ... in any interleaved order

        t1.join();  // main thread waits for t1 to finish
        t2.join();  // main thread waits for t2 to finish
        System.out.println("Both threads done");
    }
}

// CONCURRENCY — tasks making progress, not necessarily simultaneously
// Single core can do this via context switching

// Imagine: Download file + Play music on a single core
// Core switches between downloader thread and music thread rapidly
// Both 'make progress' but only one runs at each instant

// PARALLELISM — tasks running at the exact same instant
// Requires multiple cores

// 4 core CPU: all 4 threads run simultaneously

public class ConcurrencyVsParallelism {
    public static void main(String[] args) {
        int cores = Runtime.getRuntime().availableProcessors();
        System.out.println("Available cores: " + cores);

        // I/O bound task — concurrency helps even on single core
        // While Thread 1 waits for DB response, Thread 2 can serve another request
        Runnable ioTask = () -> {
            try {
                System.out.println(Thread.currentThread().getName() + " waiting for I/O");
                Thread.sleep(1000);  // simulates I/O wait
                System.out.println(Thread.currentThread().getName() + " I/O done");
            } catch (InterruptedException e) { e.printStackTrace(); }
        };

        // CPU bound task — only benefits from parallelism (more cores)
        Runnable cpuTask = () -> {
            long sum = 0;
            for (long i = 0; i < 1_000_000_000L; i++) sum += i;  // pure computation
            System.out.println(Thread.currentThread().getName() + " sum: " + sum);
        };

        // For ioTask: more threads than cores is fine — they spend most time waiting
        // For cpuTask: more threads than cores hurts — context switch overhead
    }
}

