// JVM Thread Model (modern HotSpot on Linux)
//
// USER SPACE:
// Java Thread 1 ──┐
// Java Thread 2 ──┼──→ JVM Thread Library
// Java Thread 3 ──┘
//        ↓ (1-to-1 mapping in modern JVM)
// KERNEL SPACE:
// Kernel Thread 1 (for Java Thread 1)
// Kernel Thread 2 (for Java Thread 2)
// Kernel Thread 3 (for Java Thread 3)
//        ↓
// CPU Core 1, Core 2, Core 3

public class ThreadModelDemo {
    public static void main(String[] args) throws InterruptedException {
        // Each Java thread maps to a native OS thread (KLT) in HotSpot JVM
        Thread t1 = new Thread(() -> {
            System.out.println("Running on OS thread: " + Thread.currentThread().getName());
            try { Thread.sleep(1000); } // Blocks this KLT only, not others
            catch (InterruptedException e) { e.printStackTrace(); }
        });

        Thread t2 = new Thread(() -> {
            // t2 runs independently — t1 blocking does NOT block t2
            // Because each maps to separate KLT
            System.out.println("t2 running while t1 is sleeping");
        });

        t1.start();
        t2.start();

        // Virtual Threads (Java 21+) changed this model:
        // Many virtual threads map to fewer OS threads
        // Much cheaper to create thousands of virtual threads
        // Thread.ofVirtual().start(() -> System.out.println("Virtual thread!"));
    }
}

