public class ThreadLifecycleDemo {
    public static void main(String[] args) throws InterruptedException {
        Thread thread = new Thread(() -> {
            try {
                System.out.println("Thread state inside run(): " +
                    Thread.currentThread().getState()); // RUNNABLE
                Thread.sleep(2000);  // moves to TIMED_WAITING
                System.out.println("Thread woke up");
            } catch (InterruptedException e) {
                e.printStackTrace();
            }
        });

        // State 1: NEW
        System.out.println("After new: " + thread.getState()); // NEW

        thread.start();

        // State 2: RUNNABLE (may be RUNNABLE or TIMED_WAITING depending on timing)
        System.out.println("After start: " + thread.getState()); // RUNNABLE

        Thread.sleep(500); // give thread time to enter sleep

        // State 3: TIMED_WAITING (thread is inside Thread.sleep(2000))
        System.out.println("While sleeping: " + thread.getState()); // TIMED_WAITING

        thread.join();  // main thread enters WAITING until thread finishes

        // State 4: TERMINATED
        System.out.println("After join: " + thread.getState()); // TERMINATED

        // BLOCKED state example:
        Object lock = new Object();
        Thread blocker = new Thread(() -> {
            synchronized (lock) {
                try { Thread.sleep(5000); }
                catch (InterruptedException e) { e.printStackTrace(); }
            }
        });
        Thread blocked = new Thread(() -> {
            synchronized (lock) { System.out.println("Got lock"); }
        });
        blocker.start();
        Thread.sleep(100);
        blocked.start();
        Thread.sleep(100);
        System.out.println("Blocked thread state: " + blocked.getState()); // BLOCKED
    }
}

