import java.util.concurrent.*;

public class ThreadPoolDemo {
    public static void main(String[] args) throws Exception {

        // 1. FIXED THREAD POOL — bounded, predictable
        ExecutorService fixed = Executors.newFixedThreadPool(3);
        for (int i = 1; i <= 10; i++) {
            final int taskId = i;
            fixed.execute(() -> {
                System.out.println("Task " + taskId + " on " + Thread.currentThread().getName());
                try { Thread.sleep(500); } catch (InterruptedException e) {}
            });
        }
        // 10 tasks, 3 threads — threads reused across tasks
        fixed.shutdown();

        // 2. CACHED THREAD POOL — dynamic, no limit (DANGEROUS in prod)
        ExecutorService cached = Executors.newCachedThreadPool();
        for (int i = 1; i <= 5; i++) {
            final int taskId = i;
            cached.submit(() -> {
                System.out.println("Cached task " + taskId);
                return taskId * 2;  // submit with Callable returns Future
            });
        }
        cached.shutdown();

        // 3. SCHEDULED THREAD POOL — for delayed/periodic tasks
        ScheduledExecutorService scheduled = Executors.newScheduledThreadPool(2);

        // Run once after 2 second delay
        scheduled.schedule(() -> System.out.println("Delayed task"), 2, TimeUnit.SECONDS);

        // Run every 3 seconds after initial 1 second delay
        scheduled.scheduleAtFixedRate(
            () -> System.out.println("Periodic task: " + System.currentTimeMillis()),
            1, 3, TimeUnit.SECONDS
        );

        Thread.sleep(10000);  // let tasks run
        scheduled.shutdown();
    }
}

// Real-world mapping:
// Web server handling requests      → newFixedThreadPool(n)
// API calls / I/O tasks             → newCachedThreadPool()
// Cron jobs / health checks         → newScheduledThreadPool(n)

import java.util.concurrent.*;

public class ThreadPoolDanger {
    public static void main(String[] args) {

        // DANGEROUS — no upper bound on thread count
        ExecutorService dangerous = Executors.newCachedThreadPool();
        for (int i = 0; i < 100_000; i++) {
            dangerous.submit(() -> {
                try { Thread.sleep(60_000); }  // long-running task
                catch (InterruptedException e) {}
            });
        }
        // Result: 100,000 threads created → OutOfMemoryError!

        // SAFE — explicit bounds
        ThreadPoolExecutor safePool = new ThreadPoolExecutor(
            5,                          // corePoolSize: always keep 5 threads alive
            20,                         // maximumPoolSize: never exceed 20 threads
            60L,                        // keepAliveTime: idle threads die after 60s
            TimeUnit.SECONDS,
            new LinkedBlockingQueue<>(100),  // bounded queue: max 100 pending tasks
            new ThreadPoolExecutor.CallerRunsPolicy()  // rejection: caller runs the task
        );

        // When all 20 threads busy AND 100 queue slots full:
        // CallerRunsPolicy → the thread that called submit() runs the task itself
        // This naturally slows down the submitter, creating backpressure

        // Other rejection policies:
        // AbortPolicy (default) → throws RejectedExecutionException
        // DiscardPolicy → silently drops the task
        // DiscardOldestPolicy → drops oldest queued task, retries new one

        safePool.shutdown();
    }
}

