public class StarvationDemo {

    // STARVATION CAUSE 1: Unfair lock — no guarantee of order
    static ReentrantLock unfairLock = new ReentrantLock(false);  // unfair (default)
    static ReentrantLock fairLock   = new ReentrantLock(true);   // fair — FIFO order

    // STARVATION CAUSE 2: Thread pool starvation
    static ExecutorService pool = Executors.newFixedThreadPool(2);

    public static void demonstratePoolStarvation() {
        // Both pool threads submit tasks that wait for OTHER pool tasks
        // But pool only has 2 threads — circular wait → starvation/deadlock
        pool.submit(() -> {
            Future<?> innerFuture = pool.submit(() -> "inner task");
            try {
                innerFuture.get();  // BLOCKS — waiting for inner task
                // But inner task can't run — both pool threads are blocked here!
            } catch (Exception e) { e.printStackTrace(); }
        });
    }

    // PREVENTION: Use fair lock
    static void fairLockExample() throws InterruptedException {
        Runnable task = () -> {
            fairLock.lock();
            try {
                System.out.println(Thread.currentThread().getName() + " got fair lock");
                Thread.sleep(100);
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
            } finally {
                fairLock.unlock();  // always unlock in finally!
            }
        };

        // With fair lock, threads get access in the order they requested
        for (int i = 0; i < 5; i++) {
            new Thread(task, "Thread-" + i).start();
        }
    }

    // Starvation vs Deadlock comparison:
    // Starvation: Some threads RUN, one thread NEVER gets a turn
    // Deadlock:   ALL threads BLOCKED in circular wait — zero progress
}

import java.util.concurrent.locks.*;

public class FairVsUnfairLock {
    public static void main(String[] args) throws InterruptedException {

        // NON-FAIR (default) — higher throughput, possible starvation
        ReentrantLock nonFairLock = new ReentrantLock();  // false by default

        // FAIR — guaranteed order, lower throughput
        ReentrantLock fairLock = new ReentrantLock(true);

        // Demonstration:
        demonstrateFairness(fairLock, "FAIR");
    }

    static void demonstrateFairness(ReentrantLock lock, String type) throws InterruptedException {
        Runnable task = () -> {
            for (int i = 0; i < 3; i++) {
                lock.lock();
                try {
                    System.out.println(type + " - " + Thread.currentThread().getName()
                        + " acquired lock");
                    Thread.sleep(50);
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                } finally {
                    lock.unlock();
                }
            }
        };

        Thread t1 = new Thread(task, "T1");
        Thread t2 = new Thread(task, "T2");
        Thread t3 = new Thread(task, "T3");

        t1.start(); t2.start(); t3.start();
        t1.join(); t2.join(); t3.join();

        // With FAIR lock: lock access alternates fairly among T1, T2, T3
        // With NON-FAIR lock: one thread might get multiple consecutive turns
    }

    // Summary table:
    // Feature          | Fair Lock          | Non-Fair Lock
    // Order guarantee  | FIFO               | None
    // Starvation risk  | None               | Possible
    // Throughput       | Lower              | Higher
    // Latency          | Predictable        | Variable
    // Use case         | Strict SLA tasks   | High throughput
}

public class RaceConditionDemo {
    // Shared mutable state — the source of the race condition
    static int counter = 0;

    public static void main(String[] args) throws InterruptedException {
        // Each thread increments counter 1000 times
        Thread t1 = new Thread(() -> {
            for (int i = 0; i < 1000; i++) {
                counter++;  // NOT atomic! Three steps: read → add → write
            }
        });

        Thread t2 = new Thread(() -> {
            for (int i = 0; i < 1000; i++) {
                counter++;  // same three steps, can interleave with T1
            }
        });

        t1.start();
        t2.start();
        t1.join();
        t2.join();

        System.out.println("Expected: 2000");
        System.out.println("Actual:   " + counter);  // Could be 1347, 1823, anything < 2000

        // WHY counter++ is not atomic:
        // Step 1: LOAD  — read counter value into CPU register (say: 5)
        // Step 2: ADD   — compute register + 1 = 6
        // Step 3: STORE — write 6 back to counter
        //
        // Race scenario:
        // T1: LOAD counter = 5
        //                          T2: LOAD counter = 5  ← T2 reads BEFORE T1 writes!
        //                          T2: ADD  → 6
        //                          T2: STORE counter = 6
        // T1: ADD  → 6  ← T1 still has old value 5 in its register
        // T1: STORE counter = 6  ← OVERWRITES T2's result!
        // counter = 6 instead of expected 7 — LOST UPDATE

        // Fix with AtomicInteger:
        java.util.concurrent.atomic.AtomicInteger atomicCounter =
            new java.util.concurrent.atomic.AtomicInteger(0);
        // atomicCounter.incrementAndGet() — truly atomic, no race condition
    }
}

