public class ThreadSafetyApproaches {

    // APPROACH 1: synchronized — simple but adds contention
    static int syncCounter = 0;
    static synchronized void incrementSync() {
        syncCounter++;  // only one thread at a time
    }

    // APPROACH 2: AtomicInteger — lock-free, better performance
    static AtomicInteger atomicCounter = new AtomicInteger(0);
    // atomicCounter.incrementAndGet() — atomic, no lock needed

    // APPROACH 3: Concurrent collections
    static ConcurrentHashMap<String, Integer> safeMap = new ConcurrentHashMap<>();
    // Thread-safe alternative to HashMap
    // Multiple threads can read simultaneously
    // Writes are synchronized at segment level (not whole map)

    // APPROACH 4: Immutability — no synchronization needed
    static final String CONSTANT = "This never changes";  // safe by definition

    public static void main(String[] args) throws InterruptedException {
        ExecutorService executor = Executors.newFixedThreadPool(10);

        // Test AtomicInteger thread safety
        for (int i = 0; i < 1000; i++) {
            executor.submit(() -> atomicCounter.incrementAndGet());
        }
        executor.shutdown();
        executor.awaitTermination(5, TimeUnit.SECONDS);

        System.out.println("Atomic counter (expected 1000): " + atomicCounter.get());
        // Always prints 1000 — AtomicInteger is thread-safe

        // ConcurrentHashMap usage
        ExecutorService mapExecutor = Executors.newFixedThreadPool(5);
        for (int i = 0; i < 100; i++) {
            final int key = i;
            mapExecutor.submit(() -> safeMap.put("key" + key, key));
        }
        mapExecutor.shutdown();
        mapExecutor.awaitTermination(5, TimeUnit.SECONDS);
        System.out.println("Map size (expected 100): " + safeMap.size());
    }
}

