    // SYNCHRONIZED BLOCK — explicit monitor, smaller scope
    public void incrementBlock() {
        // Non-synchronized code here runs concurrently — OK if thread-safe
        System.out.println("About to increment");

        synchronized (this) {  // only this block is mutually exclusive
            count++;  // critical section — only one thread at a time
        }

        // Non-synchronized code here also runs concurrently
        System.out.println("Done incrementing");
    }

    // Using dedicated lock object — finer control
    public void incrementWithDedicatedLock() {
        synchronized (lock) {  // locks only on 'lock' object, not 'this'
            count++;
        }
    }

    // STATIC synchronized — monitor is SynchronizedDemo.class
    public static synchronized void staticMethod() {
        // Locks the Class object — affects ALL instances
    }

    // Limitations of synchronized:
    // 1. No timeout — thread waits FOREVER for lock
    // 2. Cannot interrupt a thread waiting for synchronized lock
    // 3. No fairness — any waiting thread might get lock next
    // Solution: Use ReentrantLock which supports all three
}

import java.util.concurrent.locks.*;
import java.util.concurrent.*;

public class ReentrantLockDemo {
    private int count = 0;
    private ReentrantLock lock = new ReentrantLock();
    private ReentrantLock fairLock = new ReentrantLock(true); // fair

    // BASIC USAGE — must unlock in finally!
    public void increment() {
        lock.lock();
        try {
            count++;  // critical section
        } finally {
            lock.unlock();  // ALWAYS in finally — even if exception thrown
        }
    }

    // REENTRANCY — same thread can acquire lock it already holds
    public synchronized void outerMethod() {
        lock.lock();
        try {
            System.out.println("Outer acquired lock");
            innerMethod();  // calls another method that acquires same lock
        } finally {
            lock.unlock();
        }
    }

    public void innerMethod() {
        lock.lock();  // same thread acquiring same lock — ALLOWED (reentrant)
        try {
            System.out.println("Inner also acquired lock (same thread)");
        } finally {
            lock.unlock();  // must unlock same number of times as locked
        }
    }

    // tryLock() — non-blocking attempt
    public boolean tryIncrement() {
        if (lock.tryLock()) {  // returns immediately with true or false
            try {
                count++;
                return true;
            } finally {
                lock.unlock();
            }
        } else {
            System.out.println("Lock not available, doing something else");
            return false;
        }
    }

    // tryLock(timeout) — wait up to specified time
    public boolean timedIncrement() throws InterruptedException {
        if (lock.tryLock(3, TimeUnit.SECONDS)) {  // wait max 3 seconds
            try {
                count++;
                return true;
            } finally {
                lock.unlock();
            }
        } else {
            System.out.println("Could not acquire lock within 3 seconds");
            return false;
        }
    }
}

import java.util.concurrent.locks.*;
import java.util.*;

public class ReadWriteLockDemo {
    private Map<String, String> cache = new HashMap<>();
    private ReadWriteLock rwLock = new ReentrantReadWriteLock();
    private Lock readLock  = rwLock.readLock();
    private Lock writeLock = rwLock.writeLock();

    // READ operation — multiple threads can read simultaneously
    public String get(String key) {
        readLock.lock();  // multiple readers can hold this concurrently
        try {
            System.out.println(Thread.currentThread().getName() + " reading " + key);
            Thread.sleep(100);  // simulate slow read
            return cache.get(key);
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            return null;
        } finally {
            readLock.unlock();
        }
    }

    // WRITE operation — exclusive, blocks all readers and other writers
    public void put(String key, String value) {
        writeLock.lock();  // exclusive — no other reads or writes
        try {
            System.out.println(Thread.currentThread().getName() + " writing " + key);
            Thread.sleep(200);  // simulate slow write
            cache.put(key, value);
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        } finally {
            writeLock.unlock();
        }
    }

    // ReadWriteLock rules:
    // Read  + Read  → ALLOWED simultaneously (no blocking)
    // Read  + Write → NOT allowed (write blocks until all reads finish)
    // Write + Write → NOT allowed (exclusive)
    // Write + Read  → NOT allowed (reads blocked while write in progress)

    // When write lock is acquired:
    // → all current reads must finish
    // → no new reads can start
    // → write executes alone
    // → then reads can proceed again
}

import java.util.concurrent.*;

public class SemaphoreDemo {

    // Simulate a login system allowing max 5 concurrent sessions
    static Semaphore semaphore = new Semaphore(5);  // 5 permits

    static void loginSession(String user) {
        try {
            System.out.println(user + " waiting for session slot...");
            semaphore.acquire();  // blocks if all 5 permits taken
            System.out.println(user + " logged in. Available slots: "
                + semaphore.availablePermits());

            Thread.sleep(2000);  // simulate user session

            System.out.println(user + " logged out");
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        } finally {
            semaphore.release();  // return permit — ALWAYS in finally
        }
    }

    public static void main(String[] args) {
        // 10 users trying to log in but only 5 can be active simultaneously
        for (int i = 1; i <= 10; i++) {
            final String user = "User" + i;
            new Thread(() -> loginSession(user)).start();
        }
        // First 5 users get in immediately
        // Users 6-10 wait until one of the first 5 logs out
    }

    // Key differences: Semaphore vs Lock
    // Lock:      max 1 thread at a time, owner must unlock
    // Semaphore: max N threads at a time, any thread can release

    // BINARY SEMAPHORE (1 permit) acts like a mutex but without ownership:
    static Semaphore binarySemaphore = new Semaphore(1);
    // Thread A acquires, Thread B can release — unlike ReentrantLock
    // This is useful for producer-consumer signaling patterns
}

public class DeadlockDemo {

    static class BankAccount {
        String name;
        int balance;
        BankAccount(String name, int balance) {
            this.name = name;
            this.balance = balance;
        }
    }

    // DEADLOCK-PRONE transfer
    static void transfer(BankAccount from, BankAccount to, int amount)
            throws InterruptedException {
        synchronized (from) {  // Thread 1 locks Account A
            System.out.println(Thread.currentThread().getName()
                + " locked " + from.name);
            Thread.sleep(1000);  // exaggerate timing to trigger deadlock

            synchronized (to) {  // Thread 1 now waits for Account B
                // But Thread 2 already holds Account B!
                from.balance -= amount;
                to.balance += amount;
                System.out.println("Transfer complete");
            }
        }
    }

    public static void main(String[] args) {
        BankAccount accountA = new BankAccount("Account-A", 1000);
        BankAccount accountB = new BankAccount("Account-B", 1000);

        // T1: A → B (locks A, waits for B)
        Thread t1 = new Thread(() -> {
            try { transfer(accountA, accountB, 400); }
            catch (InterruptedException e) { e.printStackTrace(); }
        }, "T1-A-to-B");

        // T2: B → A (locks B, waits for A) — DEADLOCK!
        Thread t2 = new Thread(() -> {
            try { transfer(accountB, accountA, 500); }
            catch (InterruptedException e) { e.printStackTrace(); }
        }, "T2-B-to-A");

        t1.start(); t2.start();
        // Both threads block forever — deadlock!

        // PREVENTION — always lock in consistent order (by account ID or name)
        // Sort accounts before locking:
        // if (accountA.name.compareTo(accountB.name) < 0) { lock A first }
        // else { lock B first }
        // This eliminates circular wait condition
    }
}

import java.util.*;

public class ProducerConsumerDemo {
    private static final int BUFFER_SIZE = 5;
    private static List<Integer> buffer = new ArrayList<>();
    private static final Object lock = new Object();

    // PRODUCER
    static class Producer implements Runnable {
        @Override
        public void run() {
            int item = 0;
            while (true) {
                synchronized (lock) {
                    // WHILE — not if! Handles spurious wakeups
                    while (buffer.size() == BUFFER_SIZE) {
                        try {
                            System.out.println("Buffer full, producer waiting...");
                            lock.wait();  // releases lock and waits
                        } catch (InterruptedException e) {
                            Thread.currentThread().interrupt();
                            return;
                        }
                    }
                    buffer.add(item);
                    System.out.println("Produced: " + item + " | Buffer: " + buffer);
                    item++;
                    lock.notifyAll();  // wake up waiting consumers
                }
            }
        }
    }

    // CONSUMER
    static class Consumer implements Runnable {
        @Override
        public void run() {
            while (true) {
                synchronized (lock) {
                    // WHILE — not if! Critical for correctness
                    while (buffer.isEmpty()) {
                        try {
                            System.out.println("Buffer empty, consumer waiting...");
                            lock.wait();  // releases lock and waits
                        } catch (InterruptedException e) {
                            Thread.currentThread().interrupt();
                            return;
                        }
                    }
                    int item = buffer.remove(0);
                    System.out.println("Consumed: " + item + " | Buffer: " + buffer);
                    lock.notifyAll();  // wake up waiting producer
                }
            }
        }
    }

    // WHY while not if:
    // Scenario: Buffer empty, consumer waiting
    // Producer adds item, calls notifyAll
    // Consumer A and Consumer B both wake up
    // Consumer A gets lock first, takes item, buffer empty again
    // Consumer B wakes up — IF: proceeds without checking → error!
    // Consumer B wakes up — WHILE: rechecks buffer.isEmpty() → true → waits again!
}

public class VolatileDemo {

    // WITHOUT volatile — visibility problem
    static boolean running = true;  // might be cached in CPU cache

    // WITH volatile — always read from main memory
    static volatile boolean runningVolatile = true;

    public static void main(String[] args) throws InterruptedException {

        // WITHOUT volatile — Thread 2 might NEVER see the update from Thread 1
        Thread readerThread = new Thread(() -> {
            while (running) {  // might loop forever — cached value!
                // Thread might read stale 'true' from CPU cache
                // even after main thread sets running = false
            }
            System.out.println("Reader stopped (non-volatile)");
        });

        // WITH volatile — guaranteed visibility
        Thread volatileReader = new Thread(() -> {
            while (runningVolatile) {  // always reads from main memory
            }
            System.out.println("Volatile reader stopped");
        });

        readerThread.start();
        volatileReader.start();

        Thread.sleep(1000);
        running = false;          // might not be seen by readerThread!
        runningVolatile = false;  // GUARANTEED to be seen immediately

        // Volatile in double-checked locking Singleton:
        // private static volatile Singleton instance;
        // Without volatile: JVM might reorder object construction steps
        // Thread A: allocate memory → assign reference → initialize fields
        //           (JVM might reorder to: allocate → assign → initialize)
        // Thread B sees non-null reference but uninitialized object!
        // Volatile prevents this reordering

        // What volatile does NOT fix:
        // volatile int counter = 0;
        // counter++  is still NOT atomic — still 3 steps: read, add, write
        // Use AtomicInteger.incrementAndGet() for atomic increment
    }
}

import java.util.concurrent.locks.*;

public class MutexLockMonitorDemo {

    // MONITOR — synchronized uses the object's built-in monitor
    // Monitor = lock + condition variable bundled together
    static class MonitorExample {
        private int value = 0;
        private boolean ready = false;

        // Monitor lock (mutual exclusion)
        public synchronized void produce(int v) {
            value = v;
            ready = true;
            notifyAll();  // monitor condition signal
        }

        public synchronized int consume() throws InterruptedException {
            while (!ready) {
                wait();  // monitor condition wait — releases lock
            }
            ready = false;
            return value;
        }
    }

    // EXPLICIT LOCK + CONDITION — ReentrantLock equivalent
    static class ExplicitLockExample {
        private ReentrantLock lock = new ReentrantLock();
        private Condition condition = lock.newCondition();  // explicit condition
        private int value = 0;
        private boolean ready = false;

        public void produce(int v) {
            lock.lock();
            try {
                value = v;
                ready = true;
                condition.signalAll();  // equivalent to notifyAll()
            } finally {
                lock.unlock();
            }
        }

        public int consume() throws InterruptedException {
            lock.lock();
            try {
                while (!ready) {
                    condition.await();  // equivalent to wait()
                }
                ready = false;
                return value;
            } finally {
                lock.unlock();
            }
        }
    }

    // Summary:
    // Mutex      = concept: one thread at a time
    // Lock       = Java API: ReentrantLock, explicit control
    // Monitor    = Java's built-in: synchronized + wait/notify
    // All three achieve mutual exclusion, just at different abstraction levels
}

import java.io.*;

public class ExceptionTypesDemo {

    // CHECKED exception — compiler FORCES you to handle it
    public String readFile(String path) throws IOException {
        // If you remove 'throws IOException' and don't try-catch,
        // COMPILER ERROR: unhandled exception IOException
        BufferedReader reader = new BufferedReader(new FileReader(path));
        return reader.readLine();
    }

    // UNCHECKED exception — compiler does NOT force handling
    public int divide(int a, int b) {
        // ArithmeticException is unchecked — no throws needed, no compile error
        // But throws ArithmeticException at runtime if b == 0
        return a / b;
    }

    public static void main(String[] args) {
        ExceptionTypesDemo demo = new ExceptionTypesDemo();

        // Handling checked exception — must do one of these:
        // Option 1: try-catch
        try {
            String content = demo.readFile("test.txt");
            System.out.println(content);
        } catch (IOException e) {
            System.out.println("File error: " + e.getMessage());
            // Can recover: create default file, use backup, notify user
        }

        // Option 2: declare throws and let caller handle
        // public void processFile() throws IOException { readFile("test.txt"); }

        // Unchecked — no forced handling, runtime failure
        demo.divide(10, 0);  // throws ArithmeticException: / by zero

        // Custom checked exception
        // class InsufficientFundsException extends Exception { }

        // Custom unchecked exception
        // class InvalidAgeException extends RuntimeException { }
    }

    // Exception hierarchy:
    // Throwable
    // ├── Error (OutOfMemoryError, StackOverflowError — don't catch these)
    // └── Exception
    //     ├── RuntimeException (unchecked — NullPointerException, etc.)
    //     └── IOException, SQLException etc. (checked)
}

public class TryCatchFinallyDemo {

    public static void main(String[] args) {
        // BASIC try-catch-finally
        try {
            int[] numbers = {1, 2, 3};
            System.out.println(numbers[5]);  // throws ArrayIndexOutOfBoundsException
            System.out.println("This line never runs");
        } catch (ArrayIndexOutOfBoundsException e) {
            System.out.println("Caught: " + e.getMessage());  // runs
        } finally {
            System.out.println("Finally always runs");  // always runs
        }

        // MULTIPLE catch blocks — most specific first!
        try {
            String s = null;
            s.length();  // throws NullPointerException
        } catch (NullPointerException e) {
            System.out.println("Null pointer: " + e.getMessage());
        } catch (RuntimeException e) {
            System.out.println("Runtime: " + e.getMessage());  // not reached
        } catch (Exception e) {
            System.out.println("Exception: " + e.getMessage());  // not reached
        } finally {
            System.out.println("Cleanup");
        }

        // FINALLY runs even with return
        System.out.println("Result: " + withReturn());
        // Output:
        // In try, returning 1
        // Finally runs (even with return!)
        // Result: 1
    }

    static int withReturn() {
        try {
            System.out.println("In try, returning 1");
            return 1;
        } finally {
            System.out.println("Finally runs (even with return!)");
            // return 2;  // if you return from finally, it OVERRIDES the try return!
        }
    }

    // FINALLY does NOT run:
    // System.exit(0) → JVM terminates immediately
    // JVM crash (kill -9)
    // Infinite loop before finally
}

public class ExceptionPropagationDemo {

    public static void main(String[] args) {
        try {
            method1();  // call chain: main → method1 → method2 → method3
        } catch (ArithmeticException e) {
            System.out.println("Caught in main: " + e.getMessage());
            e.printStackTrace();
            // Stack trace (read bottom to top for root cause):
            // java.lang.ArithmeticException: / by zero
            //   at ExceptionPropagation.method3(ExceptionPropagation.java:25)  ← origin
            //   at ExceptionPropagation.method2(ExceptionPropagation.java:20)
            //   at ExceptionPropagation.method1(ExceptionPropagation.java:15)
            //   at ExceptionPropagation.main(ExceptionPropagation.java:7)      ← top
        }
    }

    static void method1() {
        System.out.println("method1 called");
        method2();
        System.out.println("method1 after method2");  // NEVER runs — exception propagated
    }

    static void method2() {
        System.out.println("method2 called");
        method3();
        System.out.println("method2 after method3");  // NEVER runs
    }

    static void method3() {
        System.out.println("method3 called");
        int result = 10 / 0;  // ArithmeticException thrown HERE
        System.out.println("method3 after division");  // NEVER runs
    }

    // Stack unwinding steps:
    // 1. method3 throws ArithmeticException
    // 2. JVM checks method3 for matching catch → NONE → pops method3 frame
    // 3. JVM checks method2 for matching catch → NONE → pops method2 frame
    // 4. JVM checks method1 for matching catch → NONE → pops method1 frame
    // 5. JVM checks main for matching catch → FOUND ArithmeticException
    // 6. Executes catch block in main → prints message
    // 7. Program continues normally after the try-catch in main
}

