class BankAccount {
    private double balance;

    public BankAccount(double balance) {
        this.balance = balance;
    }

    // 'throws' in signature — warns callers of checked exception
    public void withdraw(double amount) throws InsufficientFundsException {
        if (amount > balance) {
            // 'throw' statement — actually creates and throws the exception
            throw new InsufficientFundsException(amount - balance);
        }
        balance -= amount;
        System.out.println("Withdrew: " + amount + ", Remaining: " + balance);
    }

    public void setAge(int age) {
        // Unchecked — no 'throws' needed in signature
        if (age < 0 || age > 150) {
            throw new InvalidAgeException(age);  // throw without 'throws' declaration
        }
    }
}

