import java.util.concurrent.*;

public class ErrorHandlingStrategies {

    // FAIL FAST — detect error immediately, stop early
    public static int divide(int numerator, int denominator) {
        if (denominator == 0) {
            // Fail fast: throw immediately, don't continue with invalid state
            throw new IllegalArgumentException("Denominator cannot be zero");
        }
        return numerator / denominator;
    }

    public static void processUser(String name, int age) {
        // Fail fast: validate at entry point
        if (name == null || name.trim().isEmpty())
            throw new IllegalArgumentException("Name cannot be null or empty");
        if (age < 0 || age > 150)
            throw new IllegalArgumentException("Invalid age: " + age);
        // Only proceed if inputs are valid
        System.out.println("Processing: " + name + ", age: " + age);
    }

    // FAIL SAFE — continue with degraded response rather than crash
    private static String cachedData = "Default cached response";

    public static String fetchUserData(String userId) {
        try {
            return callExternalService(userId);  // might fail
        } catch (Exception e) {
            System.out.println("External service failed, using cached data: " + e.getMessage());
            return cachedData;  // fail safe: return cached data instead of crashing
        }
    }

    // TIMEOUT — prevent indefinite blocking
    public static String fetchWithTimeout(String userId) {
        ExecutorService executor = Executors.newSingleThreadExecutor();
        Future<String> future = executor.submit(() -> callExternalService(userId));
        try {
            return future.get(3, TimeUnit.SECONDS);  // wait max 3 seconds
        } catch (TimeoutException e) {
            future.cancel(true);
            System.out.println("Request timed out after 3 seconds");
            return cachedData;  // fallback after timeout
        } catch (Exception e) {
            return cachedData;
        } finally {
            executor.shutdown();
        }
    }

    private static String callExternalService(String userId) throws Exception {
        Thread.sleep(5000);  // simulates slow external service
        return "User data for: " + userId;
    }
}

public class JVMMemoryDemo {
    // METHOD AREA — stored here: class metadata, static variables
    static int staticVar = 100;  // in Method Area — shared by ALL instances

    // HEAP — instance variables stored in heap with the object
    int instanceVar = 10;  // in Heap — each object has its own copy

    public void display() {
        // JVM STACK — local variables stored in current stack frame
        int localVar = 20;  // in Stack — only this method invocation's frame

        // Each thread calling display() gets its OWN stack frame
        // So localVar is thread-safe — no sharing between threads

        System.out.println("Static (Method Area): " + staticVar);
        System.out.println("Instance (Heap): " + instanceVar);
        System.out.println("Local (Stack): " + localVar);
    }

    public static void main(String[] args) {
        // new JVMMemoryDemo() creates object ON THE HEAP
        // 'd1' reference variable is ON THE STACK (in main's frame)
        JVMMemoryDemo d1 = new JVMMemoryDemo();
        JVMMemoryDemo d2 = new JVMMemoryDemo();

        d1.instanceVar = 50;  // modifies d1's heap object
        System.out.println(d2.instanceVar);  // 10 — d2 has separate heap object

        JVMMemoryDemo.staticVar = 200;  // modifies Method Area
        System.out.println(d2.staticVar);   // 200 — static is shared!
    }

    // Memory areas summary:
    // Heap:        Objects and arrays. GC managed. Shared by all threads.
    // Stack:       Local variables, parameters, return addresses. Per-thread.
    // Method Area: Class metadata, static variables, bytecode. Shared.
    // PC Register: Current instruction address. Per-thread.
}

public class GarbageCollectionDemo {

    public static void main(String[] args) {
        // Object eligible for GC when no reference points to it

        // Case 1: reference set to null
        Student s1 = new Student("Harsh", 9);
        s1 = null;  // s1 no longer references the object → eligible for GC

        // Case 2: reference goes out of scope
        {
            Student s2 = new Student("Alex", 10);
        }  // s2 goes out of scope here → object eligible for GC

        // Case 3: reference reassigned
        Student s3 = new Student("Bob", 11);
        s3 = new Student("Carol", 12);  // original Bob object → eligible for GC

        // Case 4: island of isolation — objects reference each other
        // but no outside reference → ALL eligible for GC
        Student a = new Student("A", 1);
        Student b = new Student("B", 2);
        // a.friend = b; b.friend = a;  // circular reference
        a = null;
        b = null;
        // Even though a and b referenced each other,
        // no live root references them → both eligible for GC

        // You can request GC but JVM may ignore it
        System.gc();  // hint to JVM, not a command

        // Generational heap structure:
        // YOUNG GENERATION:
        //   Eden Space → new objects allocated here
        //   Survivor 0 (S0)
        //   Survivor 1 (S1)
        // When Eden fills → Minor GC:
        //   Live objects → moved to S0 or S1
        //   After several Minor GCs → promoted to OLD GENERATION
        // OLD GENERATION:
        //   Long-lived objects
        //   Full GC (slow) runs here less frequently
    }
}

