@Controller
class ChatController {
    @Autowired
    private SimpMessagingTemplate messagingTemplate;

    @MessageMapping("/chat")
    @SendTo("/topic/messages")
    public Message handleMessage(Message msg) {
        return msg;  // broadcast to ALL subscribers immediately
    }

    // Server can push to clients at any time:
    public void pushStockUpdate(StockPrice price) {
        messagingTemplate.convertAndSend("/topic/stocks", price);
        // All subscribed clients receive this INSTANTLY — no polling!
    }
}

