// RabbitMQ message flow:
// Producer → Exchange → Queue(s) → Consumer(s)

// Spring Boot RabbitMQ Producer:
@Service
class OrderService {
    @Autowired
    private RabbitTemplate rabbitTemplate;

    public void placeOrder(Order order) {
        // Save order to DB...

        // Publish to exchange — Producer's only job
        rabbitTemplate.convertAndSend(
            "events_exchange",    // exchange name
            "order.created",      // routing key
            order                 // message payload
        );
        // OrderService doesn't care who processes this or when
    }
}

// Spring Boot RabbitMQ Consumers:
@Component
class PaymentConsumer {
    @RabbitListener(queues = "payment_queue")
    public void handleOrder(Order order) {
        System.out.println("Processing payment for order: " + order.getId());
    }
}

@Component
class InventoryConsumer {
    @RabbitListener(queues = "inventory_queue")
    public void handleOrder(Order order) {
        System.out.println("Updating inventory for order: " + order.getId());
    }
}

// Exchange type examples:

// 1. DIRECT EXCHANGE (1:1) — exact routing key match
//    Binding: payment_queue ← routing key: "payment"
//    Producer sends: routing key = "payment"
//    Only payment_queue receives it

// 2. FANOUT EXCHANGE (1:N) — broadcasts to ALL bound queues
//    Order created → payment_queue, inventory_queue, email_queue ALL get it
//    Routing key ignored

// 3. TOPIC EXCHANGE — pattern matching
//    payment_queue binds to: "payment.*"
//    error_queue binds to:   "*.failed"
//    Message with key "payment.failed" → BOTH queues receive it!
//    Message with key "order.created" → neither (no matching binding)

// HTTP method idempotency:
// GET    → idempotent (read only, no side effects)
// PUT    → idempotent (set to specific value, same result every time)
// DELETE → idempotent (first call deletes, subsequent return 404 — same end state)
// POST   → NOT idempotent (creates new resource each call)
// PATCH  → depends on implementation

@RestController
class PaymentController {

    // NON-IDEMPOTENT — calling twice charges twice!
    @PostMapping("/payments")
    public Payment processPayment(@RequestBody PaymentRequest request) {
        return paymentService.charge(request.getAmount());
        // Two calls → two charges! Problem if client retries on timeout
    }

    // IDEMPOTENT POST using idempotency key
    @PostMapping("/payments/safe")
    public ResponseEntity<Payment> processPaymentSafe(
            @RequestHeader("Idempotency-Key") String idempotencyKey,
            @RequestBody PaymentRequest request) {

        // Check if we already processed this key
        Optional<Payment> existing = idempotencyStore.get(idempotencyKey);
        if (existing.isPresent()) {
            // Return cached result — do NOT process again
            return ResponseEntity.ok(existing.get());
        }

        // First time seeing this key — process and store result
        Payment payment = paymentService.charge(request.getAmount());
        idempotencyStore.save(idempotencyKey, payment);  // store with TTL (24h etc.)

        return ResponseEntity.status(201).body(payment);
    }
}

// Client sends:
// POST /payments/safe
// Idempotency-Key: abc123-unique-uuid
// { "amount": 100 }

// If client retries (network timeout):
// POST /payments/safe
// Idempotency-Key: abc123-unique-uuid  ← same key
// Server returns CACHED response, does NOT charge again

// PUT example — naturally idempotent:
// PUT /users/101 { "name": "Harsh" }
// Call 10 times → user's name is still Harsh
// Same end state every time

// Interface — the abstraction
interface RecommendationStrategy {
    List<String> recommend(String userId);
}

// Concrete implementation 1
@Service
@Primary  // Spring injects this one when multiple exist
class TrendingRecommendation implements RecommendationStrategy {
    @Override
    public List<String> recommend(String userId) {
        return List.of("Trending Movie 1", "Trending Movie 2");
    }
}

// Concrete implementation 2
@Service
class GenreRecommendation implements RecommendationStrategy {
    @Override
    public List<String> recommend(String userId) {
        return List.of("Genre Movie 1", "Genre Movie 2");
    }
}

// Netflix service — depends on INTERFACE, not concrete class
@Service
class NetflixService {

    // GOOD: interface type — follows DIP
    // Spring injects @Primary implementation (TrendingRecommendation)
    @Autowired
    private RecommendationStrategy strategy;

    // BAD: concrete type — tight coupling
    // @Autowired
    // private TrendingRecommendation strategy;  // breaks DIP

    public List<String> showRecommendations(String userId) {
        return strategy.recommend(userId);  // doesn't care which impl
    }
}

